#include <stdlib.h>
#include <string.h>
#include <time.h>

// Global key array
uint32_t key[4];

// Get the left (upper) 32 bits of a 64-bit value
uint32_t getleft(uint64_t x) {
    return (x >> 32) & 0xFFFFFFFF;
}

// Get the right (lower) 32 bits of a 64-bit value
uint32_t getright(uint64_t x) {
    return x & 0xFFFFFFFF;
