// Combine two 32-bit halves into a 64-bit value
uint64_t merge(uint32_t left, uint32_t right) {
    return ((uint64_t)(left & 0xFFFFFFFF) << 32) | (right & 0xFFFFFFFF);
}

uint32_t expand(uint32_t key) {
  return key ^ (key << 16) ^ (key * 12345);
