cat > recover.c <<'EOF'
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define NPAIRS 32
#define NSEED 0x100000

typedef struct {
    uint64_t p, c;
} Pair;

static Pair pairs[NPAIRS];

static inline uint32_t expand(uint32_t key) {
    return key ^ (key << 16) ^ (key * 12345);
}

static inline uint8_t g_function(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

static inline uint32_t f_function(uint32_t input_val) {
    uint8_t x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    uint32_t output = 0;
    for (int i = 0; i < 4; i++)
        output |= (uint32_t)y[i] << (8 * i);
    return output;
}

static inline void fwd2(uint64_t pt, uint32_t k0, uint32_t k1, uint32_t *L2, uint32_t *R2) {
    uint32_t left = (uint32_t)(pt >> 32);
    uint32_t right = (uint32_t)pt;
    right ^= left;
    uint32_t mixed = f_function(right ^ k0);
    uint32_t tr = right;
    right = left ^ mixed;
    left = tr;
    mixed = f_function(right ^ k1);
    tr = right;
    right = left ^ mixed;
    left = tr;
    *L2 = left;
    *R2 = right;
}

static inline void bwd2(uint64_t ct, uint32_t k2, uint32_t k3, uint32_t *L2, uint32_t *R2) {
    uint32_t left = (uint32_t)ct;      // right_final in decrypt.c
    uint32_t right = (uint32_t)(ct >> 32); // left_final in decrypt.c
    left ^= right;  // reverse post
    // reverse round 3 (uses k3): decrypt round: left,right before round3
    {
        uint32_t temp = left;
        left = right;
        uint32_t mixed = f_function(temp ^ k3);
        right = temp;
        left ^= mixed;
    }
    // reverse round 2 (uses k2)
    {
        uint32_t temp = left;
        left = right;
        uint32_t mixed = f_function(temp ^ k2);
        right = temp;
        left ^= mixed;
    }
    *L2 = left;
    *R2 = right;
}

int main(void) {
    FILE *fp = fopen("pairs.txt", "r");
    if (!fp) { perror("pairs.txt"); return 1; }
    for (int i = 0; i < NPAIRS; i++) {
        if (fscanf(fp, "%lu %lu", &pairs[i].p, &pairs[i].c) != 2) {
            fprintf(stderr, "bad pairs\n");
            return 1;
        }
    }
    fclose(fp);

    // Precompute expanded keys
    static uint32_t ek[4][NSEED];
    for (int i = 0; i < 4; i++)
        for (uint32_t s = 0; s < NSEED; s++)
            ek[i][s] = expand(s);

    // Build forward table for first pair: seed0 -> (seed1, L2, R2)
    // Store as sorted array or hash. Use simple hash buckets.
    // Key is 64-bit middle state; value is list of seed0seed1 candidates.
    // Memory can be large; store only for one pair. Use open addressing.
    printf("building forward table...\n");
    fflush(stdout);

    typedef struct { uint32_t sid; uint32_t L2; uint32_t R2; } FwdEntry;
    static FwdEntry *fwd[NSEED];  // bucket per hash
    static int fwdcnt[65536];

    // Use 16-bit hash of middle state
    for (uint32_t s0 = 0; s0 < NSEED; s0++) {
        uint32_t k0 = ek[0][s0];
        for (uint32_t s1 = 0; s1 < NSEED; s1++) {
            uint32_t L2, R2;
            fwd2(pairs[0].p, k0, ek[1][s1], &L2, &R2);
            uint32_t h = (L2 * 2654435761u) ^ (R2 * 40503u);
            h &= 0xFFFF;
            fwdcnt[h]++;
        }
    }
    for (int i = 0; i < 65536; i++) {
        fwd[i] = malloc(sizeof(FwdEntry) * fwdcnt[i]);
        if (!fwd[i]) { fprintf(stderr, "oom\n"); return 1; }
        fwdcnt[i] = 0;
    }
    for (uint32_t s0 = 0; s0 < NSEED; s0++) {
        uint32_t k0 = ek[0][s0];
        for (uint32_t s1 = 0; s1 < NSEED; s1++) {
            uint32_t L2, R2;
            fwd2(pairs[0].p, k0, ek[1][s1], &L2, &R2);
            uint32_t h = (L2 * 2654435761u) ^ (R2 * 40503u);
            h &= 0xFFFF;
            fwd[h][fwdcnt[h]].sid = (s0 << 20) | s1;
            fwd[h][fwdcnt[h]].L2 = L2;
            fwd[h][fwdcnt[h]].R2 = R2;
            fwdcnt[h]++;
        }
    }

    printf("searching backward...\n");
    fflush(stdout);

    for (uint32_t s3 = 0; s3 < NSEED; s3++) {
        uint32_t k3 = ek[3][s3];
        for (uint32_t s2 = 0; s2 < NSEED; s2++) {
            uint32_t L2, R2;
            bwd2(pairs[0].c, ek[2][s2], k3, &L2, &R2);
            uint32_t h = (L2 * 2654435761u) ^ (R2 * 40503u);
            h &= 0xFFFF;
            for (int idx = 0; idx < fwdcnt[h]; idx++) {
                if (fwd[h][idx].L2 == L2 && fwd[h][idx].R2 == R2) {
                    uint32_t sid01 = fwd[h][idx].sid;
                    uint32_t s0 = sid01 >> 20, s1 = sid01 & 0xFFFFF;
                    // verify all pairs
                    int ok = 1;
                    for (int i = 1; i < NPAIRS && ok; i++) {
                        uint32_t fl, fr, bl, br;
                        fwd2(pairs[i].p, ek[0][s0], ek[1][s1], &fl, &fr);
                        bwd2(pairs[i].c, ek[2][s2], ek[3][s3], &bl, &br);
                        if (fl != bl || fr != br) ok = 0;
                    }
                    if (ok) {
                        printf("FOUND %05x %05x %05x %05x\n", s0, s1, s2, s3);
                        return 0;
                    }
                }
            }
        }
        if ((s3 & 0xFFFF) == 0) { printf("s3=%05x\n", s3); fflush(stdout); }
    }

    printf("not found\n");
    return 1;
}
