#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

#define NP 32
#define N (1<<20)

typedef struct { uint64_t p, c; } Pair;
static Pair pr[NP];

static inline uint32_t expand(uint32_t key) {
    return key ^ (key << 16) ^ (key * 12345u);
}
static inline uint8_t g(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t t = (a + b + x) & 0xFF;
    return (t << 2) | (t >> 6);
}
static inline uint32_t f(uint32_t v) {
    uint8_t x[4], y[4];
    for (int i = 0; i < 4; i++) { x[i] = v & 0xFF; v >>= 8; }
    y[2] = g(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g(x[3], y[2], 0);
    y[1] = g(x[1] ^ x[0], y[2], 0);
    y[0] = g(x[0], y[1], 1);
    uint32_t r = 0;
    for (int i = 0; i < 4; i++) r |= (uint32_t)y[i] << (8 * i);
    return r;
}
static inline void round_fwd(uint32_t *L, uint32_t *R, uint32_t k) {
    uint32_t t = *R;
    *R = *L ^ f(*R ^ k);
    *L = t;
}
static inline void round_inv(uint32_t *L, uint32_t *R, uint32_t k) {
    uint32_t newL = *R ^ f(*L ^ k);
    uint32_t newR = *L;
    *L = newL; *R = newR;
}
static inline uint64_t encrypt(uint64_t pt, const uint32_t *k) {
    uint32_t L = (uint32_t)(pt >> 32), R = (uint32_t)pt;
    R ^= L;
    for (int i = 0; i < 4; i++) round_fwd(&L, &R, k[i]);
    L ^= R;
    return ((uint64_t)R << 32) | L;
}

int main(void) {
    FILE *fp = fopen("pairs.txt", "r");
    if (!fp) { perror("pairs.txt"); return 1; }
    for (int i = 0; i < NP; i++)
        if (fscanf(fp, "%lu %lu", &pr[i].p, &pr[i].c) != 2) { fprintf(stderr, "bad pairs\n"); return 1; }
    fclose(fp);

    static uint32_t ek[4][N];
    for (int i = 0; i < 4; i++)
        for (uint32_t s = 0; s < N; s++) ek[i][s] = expand(s);

    // Pair 0: precompute state after round 1 for every seed0.
    static uint32_t L1a[N], R1a[N];
    for (uint32_t s0 = 0; s0 < N; s0++) {
        uint32_t L = (uint32_t)(pr[0].p >> 32), R = (uint32_t)pr[0].p;
        R ^= L;
        round_fwd(&L, &R, ek[0][s0]);
        L1a[s0] = L; R1a[s0] = R;
    }

    // Hash table by R1 (low 20 bits) to list seed0.
    static int head[N], nxt[N];
    for (int i = 0; i < N; i++) head[i] = -1;
    for (uint32_t s0 = 0; s0 < N; s0++) {
        int h = (int)(R1a[s0] & (N - 1));
        nxt[s0] = head[h];
        head[h] = (int)s0;
    }

    // Build global table for f(x): map low 20 bits of f(x) to x.
    static int fhead[N], fnxt[N];
    static uint32_t fx[N];
    for (int i = 0; i < N; i++) fhead[i] = -1;
    for (uint32_t xv = 0; xv < N; xv++) {
        uint32_t y = f(xv);
        int h = (int)(y & (N - 1));
        fnxt[xv] = fhead[h];
        fhead[h] = (int)xv;
        fx[xv] = y;
    }

    for (uint32_t s3 = 0; s3 < N; s3++) {
        uint32_t L = (uint32_t)pr[0].c, R = (uint32_t)(pr[0].c >> 32);
        L ^= R;
        round_inv(&L, &R, ek[3][s3]); // S3
        for (uint32_t s2 = 0; s2 < N; s2++) {
            uint32_t SL = L, SR = R;
            round_inv(&SL, &SR, ek[2][s2]); // S2 = state after round2 forward
            // Forward: S2 = (R1, L1 ^ f(R1 ^ K1)) = (SL, SR)
            // So R1 = SL, L1 = SR ^ f(SL ^ K1).
            int h = (int)(SL & (N - 1));
            for (int idx = head[h]; idx != -1; idx = nxt[idx]) {
                if (R1a[idx] != SL) continue;
                uint32_t L1 = L1a[idx], R1 = SL;
                uint32_t want = SR ^ L1;
                int hh = (int)(want & (N - 1));
                for (int xv = fhead[hh]; xv != -1; xv = fnxt[xv]) {
                    if (fx[xv] != want) continue;
                    uint32_t s1 = (uint32_t)xv ^ R1;
                    uint32_t kk[4] = { ek[0][idx], ek[1][s1], ek[2][s2], ek[3][s3] };
