                    for (int i = 1; i < NP && ok; i++)
                        if (encrypt(pr[i].p, kk) != pr[i].c) ok = 0;
                    if (ok) {
                        printf("FOUND %05x %05x %05x %05x\n", idx, s1, s2, s3);
                        return 0;
                    }
                }
            }
        }
        if ((s3 & 0x3FFF) == 0) { printf("s3=%05x\n", s3); fflush(stdout); }
    }
    printf("not found\n");
    return 1;
}
